import{_ as e,a as t,b as o}from"./chunks/支持留言.NiGCLVdp.js";import{_ as n,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/blog.md","filePath":"cs-CZ/Other/blog.md","lastUpdated":1781962217000}'),p={name:"cs-CZ/Other/blog.md"};function d(r,a,c,u,g,h){return i(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Funkce Blog přidá na váš web ImgBed samostatnou blogovou stránku.</p><p>Po zapnutí ji návštěvníci otevřou na:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Domovská stránka blogu" loading="lazy"></p><p>Blog vychází z open-source projektu <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed ho přepracoval a integroval pomocí Vue, aby mohl běžet jako součást image hosting webu.</p><h2 id="kde-nastavit" tabindex="-1">Kde nastavit <a class="header-anchor" href="#kde-nastavit" aria-label="Permalink to &quot;Kde nastavit&quot;">​</a></h2><p>Nastavení blogu je v:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="Nastavení blogu" loading="lazy"></p><h2 id="prvni-nastaveni" tabindex="-1">První nastavení <a class="header-anchor" href="#prvni-nastaveni" aria-label="Permalink to &quot;První nastavení&quot;">​</a></h2><ol><li>Zapněte <code>Enable</code>.</li><li>Vyberte GitHub účet, do kterého se uloží konfigurace blogu.</li><li>Klikněte na <code>Update Blog</code>.</li><li>Počkejte na zprávu o úspěchu.</li><li>Otevřete <code>https://your-domain.com/blog/</code> a zkontrolujte blog.</li></ol><p>Při prvním použití ImgBed připraví v vybraném účtu soukromý GitHub repozitář:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Repozitář ukládá nastavení blogu a obsah článků.</p><h2 id="psani-clanku" tabindex="-1">Psaní článků <a class="header-anchor" href="#psani-clanku" aria-label="Permalink to &quot;Psaní článků&quot;">​</a></h2><p>Články upravujte v soukromém GitHub repozitáři:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typický postup:</p><ol><li>Otevřete GitHub.</li><li>Přejděte do soukromého repozitáře <code>imgbed-blog-config</code>.</li><li>Upravte nebo přidejte soubory článků.</li><li>Commitněte změny.</li><li>Vraťte se do administrace ImgBed a klikněte na <code>Update Blog</code>, nebo na domovské stránce blogu třikrát klikněte na logo vlevo nahoře, čímž spustíte aktualizaci blogu.</li></ol><p><code>Update Blog</code> nepřepisuje obsah, který jste napsali. Slouží hlavně k inicializaci repozitáře a obnovení cache blogu.</p><h2 id="podporovane-funkce" tabindex="-1">Podporované funkce <a class="header-anchor" href="#podporovane-funkce" aria-label="Permalink to &quot;Podporované funkce&quot;">​</a></h2><p>Blog podporuje běžné funkce jako seznam článků, kategorie, tagy, archiv, vyhledávání, tmavý režim a přepínání jazyků.</p><p>Podporuje také komentáře a statistiky návštěv.</p><p><img src="'+o+'" alt="Komentáře blogu" loading="lazy"></p><p>Komentáře se zobrazují pod články. Návštěvníci mohou zadat avatar, přezdívku, e-mail a text komentáře.</p><p>Statistiky ukazují zobrazení článků a návštěvy webu, což pomáhá sledovat provoz blogu.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog je vždy dostupný pod <code>/blog/</code>.</p><p>Pokud je doména ImgBed například:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>adresa blogu bude:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Po vypnutí blogu už návštěvníci blogovou stránku neotevřou.</p>',34)])])}const m=n(p,[["render",d]]);export{k as __pageData,m as default};
